// Ambient module declarations for react-syntax-highlighter deep sub-path imports.
// @types/react-syntax-highlighter only covers the top-level entry points;
// the /dist/esm/ paths are implementation details that lack their own .d.ts files.
declare module 'react-syntax-highlighter/dist/esm/prism-light';
declare module 'react-syntax-highlighter/dist/esm/languages/prism/*';
declare module 'react-syntax-highlighter/dist/esm/styles/prism';
declare module 'react-syntax-highlighter/dist/esm/styles/prism/*';
